","categories":["Dairies","Fats","Spreads","Spreadable fats","Animal fats","Dairy spreads","Milkfat","Butters"],"image":"https://images.openfoodfacts.org/images/products/611/103/700/2647/front_fr.3.400.jpg"},{"id":"6111252422411","name":"Lipton Peche ice tea","brand":"Lipton","categories":["Beverages and beverages preparations","Beverages","Tea-based beverages","Iced teas"],"image":"https://images.openfoodfacts.org/images/products/611/125/242/2411/front_en.16.400.jpg"}]$$::jsonb as j
),
p as (
  select *
  from jsonb_to_recordset((select j from data)) as x(
    id text,
    name text,
    brand text,
    categories text[],
    image text
  )
),
ins_brands as (
  insert into public.brands(name)
  select distinct p.brand
  from p
  where p.brand is not null and p.brand <> ''
  on conflict (name) do nothing
),
ins_categories as (
  insert into public.categories(name)
  select distinct c as name
  from p
  cross join unnest(p.categories) as c
  where c is not null and c <> ''
  on conflict (name) do nothing
),
upsert_products as (
  insert into public.products(id, name, brand_id, image)
  select
    p.id,
    p.name,
    b.id as brand_id,
    p.image
  from p
  left join public.brands b on b.name = p.brand
  on conflict (id) do update set
    name = excluded.name,
    brand_id = excluded.brand_id,
    image = excluded.image
)
insert into public.product_categories(product_id, category_id)
select
  p.id as product_id,
  c.id as category_id
from p
cross join unnest(p.categories) as cat_name
join public.categories c on c.name = cat_name
on conflict do nothing;

