name":"Knäckebrot Rustikal","brand":"Wasa","categories":["Plant-based foods and beverages","Plant-based foods","Cereals and potatoes","Breads","Crispbreads"],"image":"https://images.openfoodfacts.org/images/products/730/040/011/4745/front_en.54.400.jpg"},{"id":"4006229434714","name":"Bärchen-Streich","brand":"Reinert","categories":["Meats and their products","Spreads","Salted spreads"],"image":"https://images.openfoodfacts.org/images/products/400/622/943/4714/front_de.51.400.jpg"},{"id":"3800233070071","name":"Brown rice cakes","brand":"Rice Up","categories":["Plant-based foods and beverages","Plant-based foods","Cereals and potatoes","Cereals and their products","Puffed cereal cakes","Puffed rice cakes"],"image":"https://images.openfoodfacts.org/images/products/380/023/307/0071/front_en.54.400.jpg"},{"id":"3250391950805","name":"Riz basmati bio 500g","brand":"Saint Eloi","categories":["Plant-based foods and beverages","Plant-based foods","Cereals and potatoes","Seeds","Cereals and their products","Cereal grains","Rices","Aromatic rices","Indica rices","Long grain rices","White rices","Basmati rices","White Basmati rices","fr:autres-produits"],"image":"https://images.openfoodfacts.org/images/products/325/039/195/0805/front_fr.68.400.jpg"},{"id":"8425514085619","name":"Pan de centeno 51%","brand":"Mercadona","categories":["Plant-based foods and beverages","Plant-based foods","Cereals and potatoes","Cereals and their products","Breads","Rye breads"],"image":"https://images.openfoodfacts.org/images/products/842/551/408/5619/front_es.57.400.jpg"}]$$::jsonb as j
),
p as (
  select *
  from jsonb_to_recordset((select j from data)) as x(
    id text,
    name text,
    brand text,
    categories text[],
    image text
  )
),
ins_brands as (
  insert into public.brands(name)
  select distinct p.brand
  from p
  where p.brand is not null and p.brand <> ''
  on conflict (name) do nothing
),
ins_categories as (
  insert into public.categories(name)
  select distinct c as name
  from p
  cross join unnest(p.categories) as c
  where c is not null and c <> ''
  on conflict (name) do nothing
),
upsert_products as (
  insert into public.products(id, name, brand_id, image)
  select
    p.id,
    p.name,
    b.id as brand_id,
    p.image
  from p
  left join public.brands b on b.name = p.brand
  on conflict (id) do update set
    name = excluded.name,
    brand_id = excluded.brand_id,
    image = excluded.image
)
insert into public.product_categories(product_id, category_id)
select
  p.id as product_id,
  c.id as category_id
from p
cross join unnest(p.categories) as cat_name
join public.categories c on c.name = cat_name
on conflict do nothing;

commit;

